public class InMemoryQueueLibrary {
    private final Map<String, InMemoryQueue> queue =
        new ConcurrentHashMap<>(); // holds all queues

    public InMemoryQueueLibrary() {
        ScheduledExecutorService scheduler =
            Executors.newSingleThreadScheduledExecutor();
        scheduler.scheduleAtFixedRate(() {
            queues.values.forEach(InMemotyQueue::cleanup);
        }, 1, 1, TimeUnit.SECONDS);
    }

    public void createQueue(String name, long retentionPeriodMillis) {
        queues.putIfAbsent(
            name, new InMemoryQueue(name, retentionPeriodMillis));
    }

    public void publish(String name, String message, Long ttlMillis) {
        // Find queue and publish the message
        InMemoryQueue = queues.get(name);
        if (queue != null) {
            queue.publish(message, ttlMilis);
        }
    }

    public void subscribe(String name, String subscriberId) {
        // Register a subscriber
        InMemoryQueue = queues.get(name);
        if (queue != null) {
            queue.subscribe(subscriberId);
        }
    }

    public List<String> pull(String name, String subscriberId) {
        InMemoryQueue = queues.get(name);
        if (queue == null) {
            return Collections.emptyList();
        }
        return queue.pull(subscriberId);
    }
}
