class InMemoryQueue {
    private final name; // queue name
    private final long retentionPeriodMillis; // max retention period
    private final Deque<QueueMessage> messages =
        new ConcurrentDeque<>(); // thread-safe deque
    private final Map<String, Integer> subscriberOffsets =
        new ConcurrentHashMap<>() // subscriber read offsets

        public InMemoryQueue(String name, long retentionPeriodMillis) {
        this.name = name;
        this.retentionPeriodMillis = retentionPeriodMillis;
    }

    public void publish(String payload, Long ttlMillis) {
        // Append new message with timestamp and optional TTL
        messages.addLast(
            new QueueMessage(payload, System.currentTimeMillis(), ttlMillis));
    }

    public void subscribe(String subscriberId) {
        // initialise subscriber offset to start of the queue
        subscriberOffsets.putIfAbsent(subscriberId, 0);
    }

    public List<String> pull(String subscriberId) {
        List<String> result = new ArrayList<>();
        if (!subscriberOffsets.containsKey(subscriberId)) {
            return result;
        }

        int offset = subscriberOffsets.get(subscriberId); // where they left off
        int idx = 0;
        for (QueueMessage msg : messages) {
            if (idx >= offset && !msg.isExpired(retentionPeriodMillis)) {
                // add non expired message
                result.add(msg.getPayload());
            }
            idx++;
        }
        subscriberOffsets.put(subscriberId, idx);
        return result;
    }

    public void cleanup() {
        long now = System.currentTimeMillis();
        while (true) {
            QueueMessage head = messages.peekFirst();
            if (head == null) {
                break; // no messages to clean
            }
            if (!head.isExpired(retentionPeriodMillis)) {
                break; // head is still fresh
            }

            messages.pollFirst(); // remove the expired head
            // shift every subscriber offset by one
            subscriberOffsets.replaceAll((id, off) -> off > 0 ? off - 1 : 0);
        }
    }
}
