class QueueMessage {
    private final String payload; // message content
    private final long timestamp; // creation time
    private final Long ttlMillis; // optional TTL

    public QueueMessage(String payload, long timestamp, Long ttlMillis) {
        this.payload = payload;
        this.timestamp = timestamp;
        this.ttlMillis = ttlMillis;
    }

    public String getPayload() {
        return payload;
    }
    public long getTimestamp() {
        return timestamp;
    }
    public Long getTtlMillis() {
        return ttlMillis;
    }

    public boolean isExpired(long retentionPeriodMillis) {
        long now = System.currentTimeMillis();
        boolean byTTL = ttlMillis != null && now - timestamp > ttlMillis;
        boolean byRentention = now - timestamp > retentionPeriodMillis;

        return byTTL || byRetention;
    }
}
